class ThemeIcons:
    """主题色 SVG 图标（HiDPI 友好）。"""

    _cache: dict[str, QIcon] = {}

    @classmethod
    def pixmap(cls, name: str, size: int = 20, color: str = "#6366f1") -> QPixmap:
        if name not in _SVGS:
            name = "help"
        svg = _SVGS[name].replace("currentColor", color)
        renderer = QSvgRenderer(QByteArray(svg.encode("utf-8")))
        dpr = 2
        pm = QPixmap(size * dpr, size * dpr)
        pm.fill(Qt.GlobalColor.transparent)
        p = QPainter(pm)
        p.setRenderHint(QPainter.RenderHint.Antialiasing, True)
        p.setRenderHint(QPainter.RenderHint.SmoothPixmapTransform, True)
        renderer.render(p, QRectF(0, 0, size * dpr, size * dpr))
        p.end()
        pm.setDevicePixelRatio(dpr)
        return pm

    @classmethod
    def icon(cls, name: str, size: int = 20, color: str = "#6366f1") -> QIcon:
        key = f"{name}:{size}:{color}"
        if key not in cls._cache:
            cls._cache[key] = QIcon(cls.pixmap(name, size, color))
        return cls._cache[key]

    @classmethod
    def icon_same_when_disabled(
        cls, name: str, size: int = 20, color: str = "#6366f1"
    ) -> QIcon:
        """禁用态仍使用主色图标，避免 QPushButton:disabled 将图标压成灰色。"""
        key = f"{name}:{size}:{color}:sameDis"
        if key not in cls._cache:
            pm = cls.pixmap(name, size, color)
            ic = QIcon()
            ic.addPixmap(pm, QIcon.Mode.Normal, QIcon.State.Off)
            ic.addPixmap(pm, QIcon.Mode.Disabled, QIcon.State.Off)
            ic.addPixmap(pm, QIcon.Mode.Active, QIcon.State.Off)
            cls._cache[key] = ic
        return cls._cache[key]

    @classmethod
    def clear_cache(cls):
        cls._cache.clear()
